then.script:
               var reqJson = mc.getProperty("reqPayload");
                   var log = mc.getServiceLog();
if (typeof reqJson === "string") {
       reqJson = JSON.parse(reqJson);
   }
   log.info(typeof reqJson);
   log.info(reqJson);
   log.info(reqJson.payoutId);
               var response = {
                   payoutId: reqJson.payoutId,
                   amount: reqJson.amount,
                   currency: reqJson.currency || "usd",
                   arrivalDate: reqJson.arrivalDate,
                   isSuccess: true,
                   message: "Successfully store the payment."
               };

               // Conditionally add fields if they exist
               if (reqJson.policyNumber != null && reqJson.policyNumber != undefined) {
                   response.policyNumber = reqJson.policyNumber;
               }

               if (reqJson.quoteId != null && reqJson.quoteId != undefined) {
                   response.quoteId = reqJson.quoteId;
               }

               if (reqJson.partyIdentifier != null && reqJson.partyIdentifier != undefined) {
                   response.partyIdentifier = reqJson.partyIdentifier;
               }

               mc.setPayloadJSON(response);
